export const getTasks = () =>
  Promise.resolve({ data: { data: tasks } });

export const createTask = (data) => {
  const newTask = {
    ...data,
    _id: Math.random().toString(36).slice(2), // 🔌 Use _id
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  tasks.push(newTask);
  return Promise.resolve({ data: { data: newTask } });
};

export const updateTask = (id, data) => {
  tasks = tasks.map(t =>
    t._id === id ? { ...t, ...data, updatedAt: new Date().toISOString() } : t // 🔌 Check against _id
  );
  const updated = tasks.find(t => t._id === id);
  return Promise.resolve({ data: { data: updated } });
};

export const deleteTask = (id) => {
  tasks = tasks.filter(t => t._id !== id); // 🔌 Filter against _id
  return Promise.resolve({ data: { success: true } });
};
